import Foundation

func solve(nums: [Int64]) -> Int64 {
    let sorted = nums.sorted { a, b in abs(a) < abs(b) }
    var total = 0
    for i in 0..<sorted.count {
        let target = 2 * abs(sorted[i])
        var low = i + 1
        var high = sorted.count
        while low < high {
            let mid = (low + high) / 2
            if sorted[mid] <= target {
                low = mid + 1
            } else {
                high = mid
            }
        }
        total += low - (i + 1)
    }
    return total
}
