func solve(nums: [Int64]) -> Int64 {
    let absValues = nums.map { abs($0) }
    let sortedAbs = absValues.sorted()
    var count = 0
    let n = sortedAbs.count
    for i in 0..<n {
        let target = 2 * sortedAbs[i]
        var left = i + 1
        var right = n - 1
        var res = i
        while left <= right {
            let mid = (left + right) / 2
            if sortedAbs[mid] <= target {
                res = mid
                left = mid + 1
            } else {
                right = mid - 1
            }
        }
        count += res - i
    }
    return Int64(count)
}
